        }

        return false;
    }

    /**
     * Checks if all elements in nums1 can be transformed to have parity P.
     * P = 0 for Even, P = 1 for Odd.
     */
    private static boolean checkParity(int P, long[] nums1, long M) {
        int n = nums1.length;

        for (int i = 0; i < n; i++) {
            long x = nums1[i];

            // Case A: x is the minimum element M. No subtraction choice available.
            if (x == M) {
                // Must choose nums2[i] = x. Check its parity.
                if ((x % 2) != P) {
                    return false;
                }
                continue;
            }

            // Case B: x > M. We have choices: x or x - M.

            // Choice 1: nums2[i] = x
            int parity1 = (int) (x % 2);

            // Choice 2: nums2[i] = x - M. Since x > M, x - M >= 1.
            // We check parity of (x - M).
            // Parity of (x - M) is (x mod 2) XOR (M mod 2).
            int parity2 = (int) ((x - M) % 2);

